PRAGMA writable_schema=ON;
CREATE VIEW daily_api_usage_summary AS
SELECT
  user_id,
  date,
  SUM(request_count) as total_requests,
  COUNT(*) as total_operations,
  SUM(CASE WHEN is_success = 1 THEN 1 ELSE 0 END) as successful_operations,
  SUM(CASE WHEN is_success = 0 THEN 1 ELSE 0 END) as failed_operations,
  AVG(response_time_ms) as avg_response_time_ms,
  MAX(response_time_ms) as max_response_time_ms
FROM google_ads_api_usage
GROUP BY user_id, date;
CREATE VIEW v_login_stats AS
SELECT
    username_or_email,
    COUNT(*) as total_attempts,
    SUM(CASE WHEN success = 1 THEN 1 ELSE 0 END) as successful_logins,
    SUM(CASE WHEN success = 0 THEN 1 ELSE 0 END) as failed_logins,
    MAX(attempted_at) as last_attempt,
    device_type,
    os,
    browser
FROM login_attempts
GROUP BY username_or_email, device_type, os, browser;
CREATE VIEW v_user_audit_stats AS
SELECT
    operator_id,
    operator_username,
    event_type,
    COUNT(*) as operation_count,
    MAX(created_at) as last_operation,
    SUM(CASE WHEN status = 'success' THEN 1 ELSE 0 END) as success_count,
    SUM(CASE WHEN status = 'failure' THEN 1 ELSE 0 END) as failure_count
FROM audit_logs
WHERE event_type LIKE 'user_%'
GROUP BY operator_id, operator_username, event_type;
CREATE TRIGGER prevent_duplicate_mcc_assignment
BEFORE INSERT ON user_mcc_assignments
FOR EACH ROW
BEGIN
  SELECT CASE
    WHEN EXISTS (SELECT 1 FROM user_mcc_assignments WHERE mcc_customer_id = NEW.mcc_customer_id AND user_id != NEW.user_id)
    THEN RAISE(ABORT, 'MCC 账号已被其他用户绑定')
  END;
END;
